B.Kn=s([B.QI,B.QS,B.QL,B.QM,B.QJ,B.QP],t.dO)
B.QV=new A.zC("How the issue was identified",B.Kn,null)
B.R3=new A.zE("Perfect Pet Insurance","Pet Insurance Quote Flow redesign","This project focused on the quote and review journey for Perfect Pet Insurance, specifically the stage where users review the details of their selected policy before deciding whether to continue to purchase. The redesign aimed to improve clarity, trust, and readability at a critical decision point, particularly for users arriving from comparison sites with limited context and little familiarity with insurance terminology.","Case study 01",null)
B.R4=new A.tl(null)
B.JT=s(["Internal testing suggested that the revised flow was easier to understand and felt more credible, particularly in terms of readability and structure.","The redesigned Review Details experience is now being prepared for A/B testing in Amplitude, with results expected over the next few weeks.","Once the experiment has run long enough to produce reliable findings, this case study will be updated with completion data and any broader behavioural changes.","A key learning from the project was that improving visual polish alone would not have been enough. The most meaningful change came from reducing the effort required for users to understand what they were reviewing."],t.s)
B.R6=new A.zF(B.cr,"What happens next",B.JT,null)
B.Rd=new A.d3("Role","UX research and design")
B.Rk=new A.d3("Product","Perfect Pet Insurance \u2014 Quote Flow")
B.R7=new A.d3("Team","Me, front-end dev, QA, BA")
B.Rc=new A.d3("Timeline","2 weeks")
B.JH=s([B.Rd,B.Rk,B.R7,B.Rc],t.GN)
B.Ro=new A.zG(B.JH,null)
B.Rw=new A.hc("Clarity","Policy details easier to scan and interpret")
B.Rq=new A.hc("Trust","Reassurance built into the journey")
B.Rp=new A.hc("Structure","Improved hierarchy and visual balance")
B.Rt=new A.hc("Progression","Designed to support completion")
B.JA=s([B.Rw,B.Rq,B.Rp,B.Rt],t._1)
B.Ry=new A.zH(B.JA,null)
B.Rh=new A.d3("Objective","Improve clarity, trust, and completion")
B.R9=new A.d3("Users","Pet owners reviewing quotes online")
B.Rf=new A.d3("Constraints","FCA compliance, legacy continuity, MudBlazor")
B.Rb=new A.d3("Success measure","Completion rate and user confidence")
B.Ka=s([B.Rh,B.R9,B.Rf,B.Rb],t.GN)
B.RB=new A.zI("Perfect Pet Insurance\u2019s quote journey allows users to select cover, review the details of their policy, and then continue towards purchase. The Review Details stage sits at the point where a user stops to assess what they are actually buying: what level of cover they have chosen, what is included, and whether the overall price and proposition feel right for them. It is a critical point in the journey because it is where uncertainty tends to surface most clearly.","The existing experience made that assessment harder than it needed to be. The page relied heavily on dense text blocks, offered limited visual hierarchy, and lacked the reassurance cues needed to support confident decision-making. For users arriving from aggregator journeys, this was especially problematic. Many were encountering the brand mid-funnel, with limited context, and needed a quick, clear understanding of what they were reviewing. The redesign therefore needed to make the journey easier to understand without reducing essential policy detail or compromising compliance.",B.Ka,null)
B.RI=new A.fC("Reviewed behavioural evidence","I began by reviewing session recordings, internal feedback, and the existing journey to ensure the redesign was grounded in user behaviour rather than visual preference alone.")
B.RG=new A.fC("Benchmarked the category","I reviewed other pet insurance and aggregator-linked experiences to understand how comparable journeys used structure, reassurance, and branding to support decision-making.")
B.RF=new A.fC("Conducted a heuristic audit","Using Nielsen Norman heuristics, I evaluated the existing flow against established usability principles such as clarity, consistency, and visibility of system status.")
B.RC=new A.fC("Explored solutions within constraints","Working with the BA and front-end developer, I developed layout directions that improved legibility and trust while remaining realistic within MudBlazor and compliant with required policy language.")
B.RD=new A.fC("Validated the redesign internally","Once the revised Review Details stage had been finalised, it went through internal usability testing to assess comprehension, confidence, and task completion before live experimentation.")
B.HV=s([B.RI,B.RG,B.RF,B.RC,B.RD],t.DD)
B.RL=new A.zJ("Approach",B.HV,null)
B.RO=new A.zK("The issue was not a lack of demand. It was the amount of effort users had to expend to understand the product and feel confident proceeding.","Summary of the core finding across research and internal feedback",null)
